mapper.select:
select cl.id as class_id, cl.*, co.course_name, co.course_type,
t.id as teacher_id, t.username as teacher_username, cr.id as cr_id, cr.course_rest_time from class_student as cs left join class as cl on cs.class_id = cl.id left join course as co on cl.course_id = co.id
left join class_teacher as ct on ct.class_id = cl.id left join teacher as t on ct.teacher_id = t.id left join course_record as cr on cr.student_id = cs.student_id and cr.course_id = cl.course_id where cs.student_id = #{studentId}
